export const getListHandoverNotesUrl = (venueId: number,
    params?: ListHandoverNotesParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/venues/${venueId}/handover-notes?${stringifiedParams}` : `/api/venues/${venueId}/handover-notes`
}

