export const getListPrepLibraryTasksUrl = (venueId: number,
    params?: ListPrepLibraryTasksParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/venues/${venueId}/prep-library?${stringifiedParams}` : `/api/venues/${venueId}/prep-library`
}

