export const getListTemperatureLogsUrl = (venueId: number,
    params?: ListTemperatureLogsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/venues/${venueId}/temperature/logs?${stringifiedParams}` : `/api/venues/${venueId}/temperature/logs`
}

